namespace AlaigalBE.Controllers;

public static class ThirukkuralData
{
    public static readonly List<KuralDto> Kurals = new()
    {
        new(1, "அகர முதல எழுத்தெல்லாம் ஆதி\nபகவன் முதற்றே உலகு.", "எழுத்துக்கள் எல்லாம் அகரத்தை முதலாக கொண்டிருப்பது போல், உலகம் கடவுளை முதலாக கொண்டிருக்கிறது."),
        new(2, "கற்றதனால் ஆய பயனென்கொல் வாலறிவன்\nதற்றுணர்வார்ப் பேணாக் கடை.", "கற்றதனால் என்ன பயன்? தூய அறிவுடைய கடவுளை உணர்ந்தவர்களை மதிக்காவிட்டால்."),
        new(3, "மலர்மிசை ஏகினான் மாணடி சேர்ந்தார்\nநிலமிசை நீடுவாழ் வார்.", "மலர் மேல் நடந்தவனின் சிறந்த திருவடிகளை சேர்ந்தவர்கள் இந்த உலகில் நீண்ட காலம் வாழ்வார்கள்."),
        new(4, "வேண்டுதல் வேண்டாமை இலானடி சேர்ந்தார்க்கு\nயாண்டும் இடும்பை இல.", "விருப்பு வெறுப்பு இல்லாத கடவுளின் திருவடிகளை சேர்ந்தவர்களுக்கு எங்கும் துன்பம் இல்லை."),
        new(5, "இருள்சேர் இருவினையும் சேரா இறைவன்\nபொருள்சேர் புகழ்புரிந்தார் மாட்டு.", "கடவுளின் உண்மையான புகழை விரும்பினவர்களிடம் இருளான இரு வினைகளும் சேரா."),
        new(6, "பொறிவாயில் ஐந்தவித்தான் பொய்தீர் ஒழுக்க\nநெறிநின்றார் நீடுவாழ் வார்.", "ஐம்புலன்களையும் அடக்கியவனின் பொய்யற்ற ஒழுக்க நெறியில் நின்றவர்கள் நீண்ட காலம் வாழ்வார்கள்."),
        new(7, "தனக்குவமை இல்லாதான் தாள்சேர்ந்தார்க் கல்லால்\nமனக்கவலை மாற்றல் அரிது.", "தனக்கு ஒப்பில்லாத கடவுளின் திருவடிகளை சேர்ந்தவர்களுக்கு மட்டுமே மனக்கவலை நீங்கும்."),
        new(8, "அறவாழி அந்தணன் தாள்சேர்ந்தார்க் கல்லால்\nபிறவாழி நீந்தல் அரிது.", "அறக்கடலான கடவுளின் திருவடிகளை சேர்ந்தவர்களுக்கு மட்டுமே பிறவிக்கடலை கடக்க முடியும்."),
        new(9, "கோளில் பொறியின் குணமிலவே எண்குணத்தான்\nதாளை வணங்காத் தலை.", "எட்டு குணங்களுடைய கடவுளின் திருவடிகளை வணங்காத தலை, குணமற்ற உறுப்பு போன்றது."),
        new(10, "பிறவிப் பெருங்கடல் நீந்துவர் நீந்தார்\nஇறைவன் அடிசேரா தார்.", "கடவுளின் திருவடிகளை சேராதவர்கள் பிறவிப் பெருங்கடலை கடக்க மாட்டார்கள்."),
        new(11, "வான்நின்று உலகம் வழங்கி வருதலால்\nதான்அமிழ்தம் என்றுணரற் பாற்று.", "மழை நின்று உலகை வாழ வைப்பதால், அது அமிழ்தம் என்று அறியப்படுகிறது."),
        new(12, "துப்பார்க்குத் துப்பாய துப்பாக்கித் துப்பார்க்குத்\nதுப்பாய தூஉம் மழை.", "உண்பவர்களுக்கு உணவை விளைவிக்கும் மழையே, உண்பவர்களுக்கு உணவாகவும் இருக்கிறது."),
        new(13, "விண்இன்று பொய்ப்பின் விரிநீர் வியனுலகத்து\nமண்இன்று ஆகி விடும்.", "மழை இல்லாவிட்டால், விரிந்த நீரையுடைய இந்த உலகம் மண்ணற்றதாகி விடும்."),
        new(14, "ஏரின் உழாஅர் உழவர் புயல்என்னும்\nவாரி வளங்குன்றிக் கால்.", "மழை என்னும் வளம் குறைந்தால், உழவர்கள் ஏர் கொண்டு உழ மாட்டார்கள்."),
        new(15, "கெடுப்பதூஉம் கெட்டார்க்குச் சார்வாய்மற் றாங்கே\nவிடுப்பதூஉம் வீழ்செய்வது மழை.", "மழை கெடுப்பதும், கெட்டவர்களுக்கு துணையாவதும், விடுவிப்பதும் அதுவே செய்கிறது."),
        new(16, "உரன்என்னும் தோட்டியான் ஓரைந்தும் காப்பான்\nவரன்என்னும் வைப்பிற்கோர் வித்து.", "மனவலிமை என்னும் அங்குசத்தால் ஐம்புலன்களையும் காப்பவன், சிறந்த செல்வத்திற்கு விதை."),
        new(17, "யாகாவா ராயினும் நாகாக்க காவாக்கால்\nசோகாப்பர் சொல்லிழுக்குப் பட்டு.", "எதை காக்காவிட்டாலும், நாவை காக்க வேண்டும். காக்காவிட்டால் சொல் தவறால் துன்பப்படுவர்."),
        new(18, "ஒன்றானும் தீச்சொல் பொருட்பயன் உண்டாயின்\nநன்றாகா தாகி விடும்.", "ஒரு தீய சொல்லாலும் பயன் உண்டாயின், நன்மை ஆகாமல் போய்விடும்."),
        new(19, "தீயினாற் சுட்டபுண் உள்ளாறும் ஆறாதே\nநாவினாற் சுட்ட வடு.", "தீயால் சுட்ட புண் ஆறும், ஆனால் நாவால் சுட்ட வடு ஆறாது."),
        new(20, "கதங்காக்க கற்றடங்கல் ஆற்றுவார்க்கு அஃதே\nமதங்காக்க மாக்கதம் தேர்வு.", "கோபத்தை அடக்கி கற்றவர்களுக்கு, அதுவே மதத்தை காக்கும் சிறந்த வழி."),
        new(21, "செய்யாமல் செய்த உதவிக்கு வையகமும்\nவானகமும் ஆற்றல் அரிது.", "எதிர்பாராமல் செய்த உதவிக்கு, இந்த உலகமும் வானுலகமும் கைமாறு செய்ய இயலாது."),
        new(22, "மிகுதியான் மிக்கவை செய்தாரைத் தாந்தம்\nவகுதியான் வென்று விடல்.", "மிகுதியாக தீமை செய்தவர்களை, தாமே தம் வகையால் வெல்லலாம்."),
        new(23, "இன்னா செய்தாரை ஒறுத்தல் அவர்நாண\nநன்னயம் செய்து விடல்.", "தீமை செய்தவர்களை தண்டிக்க, அவர்கள் வெட்கப்படும்படி நன்மை செய்வதே சிறந்தது."),
        new(24, "மறந்தும் பிறன்கேடு சூழற்க சூழின்\nஅறஞ்சூழும் சூழ்ந்தவன் கேடு.", "மறந்தும் பிறர் கேட்டை நினைக்காதே. நினைத்தால், அறம் அவனையே கெடுக்கும்."),
        new(25, "நிலையின் திரியாது அடங்கியான் தோற்றம்\nமலையினும் மாணப் பெரிது.", "நிலையில் மாறாமல் அடங்கியவனின் பெருமை மலையை விட மிகவும் பெரியது."),
        new(26, "ஒழுக்கம் விழுப்பந் தரலான் ஒழுக்கம்\nஉயிரினும் ஓம்பப் படும்.", "ஒழுக்கம் சிறப்பை தருவதால், ஒழுக்கம் உயிரை விட மேலாக காக்கப்படுகிறது."),
        new(27, "எப்பொருள் யார்யார்வாய்க் கேட்பினும் அப்பொருள்\nமெய்ப்பொருள் காண்பதறிவு.", "எந்தப் பொருளை யார் யார் வாயில் கேட்டாலும், அந்தப் பொருளின் உண்மையை காண்பதே அறிவு."),
        new(28, "எண்பதத்தான் ஓரா முறைசெய்யா மன்னவன்\nதண்பதத்தான் தானே கெடும்.", "எளிமையான முறையில் நீதி செய்யாத அரசன், தானே தன் குளிர்ந்த நிலையில் கெடுவான்."),
        new(29, "கொலைஞர் உலகத்து மேலாயினும் தன்னை\nவிலைஞர் கொளல்வேண்டும் ஆங்கு.", "கொலைஞர் உலகில் மேலானவராயினும், தன்னை விலைக்கு கொள்ள வேண்டும்."),
        new(30, "அன்பிலார் எல்லாம் தமக்குரியர் அன்புடையார்\nஎன்பும் உரியர் பிறர்க்கு.", "அன்பில்லாதவர்கள் எல்லாவற்றையும் தமக்கே என்று வைத்திருப்பர். அன்புடையவர்கள் தம் எலும்பும் பிறருக்கு உரியது என்று கருதுவர்."),
        new(31, "அன்பிற்கும் உண்டோ அடைக்குந்தாழ் ஆர்வலர்\nபுன்கணீர் பூசல் தரும்.", "அன்புக்கும் தாழிட முடியுமா? விரும்பியவர்களின் கண்ணீர் அதை திறந்துவிடும்."),
        new(32, "அன்போடு இயைந்த வழக்கென்ப ஆருயிர்க்கு\nஎன்போடு இயைந்த தொடர்பு.", "அன்போடு கூடிய உறவு, உயிருக்கு எலும்போடு கூடிய தொடர்பு போன்றது."),
        new(33, "அன்பு ஈனும் ஆர்வம் உடைமை அதுஈனும்\nநண்பு என்னும் நாடாச் சிறப்பு.", "அன்பு ஆர்வத்தை தரும். அது அளவிட முடியாத நட்பு என்னும் சிறப்பை தரும்."),
        new(34, "அன்பகத் தில்லா உயிர்வாழ்க்கை வன்பாற்கண்\nவற்றல் மரந்தளிர்த் தற்று.", "அன்பில்லாத உயிர் வாழ்க்கை, கடினமான நிலத்தில் வற்றிய மரம் தளிர்த்தது போன்றது."),
        new(35, "அன்பின் வழியது உயிர்நிலை அஃதிலார்க்கு\nஎன்புதோல் போர்த்த உடம்பு.", "அன்பின் வழியே உயிர் நிலைக்கிறது. அன்பில்லாதவர்களுக்கு உடல் எலும்பை தோல் மூடியது மட்டுமே."),
        new(36, "அறத்தாறு இதுவென வேண்டா சிவிகை\nபொறுத்தானோடு ஊர்ந்தான் இடை.", "அறத்தின் வழி இது என்று சொல்ல வேண்டாம். பல்லக்கை சுமந்தவனுக்கும் அதில் ஏறியவனுக்கும் இடையே உள்ள வேறுபாடே அது."),
        new(37, "வீழ்நாள் படாமை நன்றாற்றின் அஃதொருவன்\nவாழ்நாள் வழியடைக்கும் கல்.", "நல்லது செய்யாத நாள் கழியாமல் இருந்தால், அது ஒருவனின் வாழ்நாள் வழியை அடைக்கும் கல்லாகும்."),
        new(38, "அருள்சேர்ந்த நெஞ்சினார்க் கில்லை இருள்சேர்ந்த\nஇன்னா உலகம் புகல்.", "அருள் நிறைந்த மனத்தினர்க்கு இருளான துன்ப உலகில் புகுதல் இல்லை."),
        new(39, "மன்னுயிர் ஓம்பி அருளாள்வார்க்கு இல்லென்ப\nதுன்பம் வரினும் உளது.", "உயிர்களை காத்து அருளால் ஆள்பவர்களுக்கு துன்பம் வந்தாலும் இல்லை என்று சொல்வர்."),
        new(40, "அருள்இல்லார்க்கு அவ்வுலகம் இல்லை பொருள்இல்லார்க்கு\nஇவ்வுலகம் இல்லாகி யாங்கு.", "அருளில்லாதவர்களுக்கு மறுவுலகம் இல்லை. பொருளில்லாதவர்களுக்கு இவ்வுலகம் இல்லாதது போல."),
        new(41, "தவமும் தவமுடையார்க்கு ஆகும் அவமே\nஅவமாம் தவமில்லா தார்க்கு.", "தவம் தவமுடையவர்களுக்கே பயன்படும். தவமில்லாதவர்களுக்கு அது வீணே."),
        new(42, "துறந்தார் பெருமை துணைக்கூறின் வையத்து\nஇறந்தாரை எண்ணிக்கொண் டற்று.", "துறந்தவர்களின் பெருமையை அளவிட்டால், இறந்தவர்களை எண்ணுவது போல் முடிவில்லாதது."),
        new(43, "ஒல்லும் வகையான் அறவினை ஓவாதே\nசெல்லும்வாய் எல்லாம் செயல்.", "முடிந்த வகையில் அறச்செயலை விடாமல், செல்லும் இடமெல்லாம் செய்."),
        new(44, "மனத்துக்கண் மாசிலன் ஆதல் அனைத்தறன்\nஆகுல நீர பிற.", "மனத்தில் குற்றமில்லாமல் இருப்பதே அறம். மற்றவை எல்லாம் ஆரவாரமே."),
        new(45, "அழுக்காறு அவாவெகுளி இன்னாச்சொல் நான்கும்\nஇழுக்கா இயன்றது அறம்.", "பொறாமை, ஆசை, கோபம், கடுஞ்சொல் ஆகிய நான்கும் இல்லாமல் இயங்குவதே அறம்."),
        new(46, "அன்றறிவாம் என்னாது அறஞ்செய்க மற்றது\nபொன்றுங்கால் பொன்றாத் துணை.", "பிறகு செய்வோம் என்று சொல்லாமல் அறம் செய். அது இறக்கும்போது அழியாத துணை."),
        new(47, "அறத்தான் வருவதே இன்பம் மற்றெல்லாம்\nபுறத்த புகழும் இல.", "அறத்தால் வருவதே இன்பம். மற்றவை எல்லாம் புகழும் இல்லாத வெளிப்பொருள்."),
        new(48, "சிறப்பீனும் செல்வமும் ஈனும் அறத்தினூஉங்கு\nஆக்கம் எவனோ உயிர்க்கு.", "சிறப்பையும் செல்வத்தையும் தரும் அறத்தை விட உயிருக்கு வேறு என்ன ஆக்கம் இருக்கும்?"),
        new(49, "அறத்தினூஉங்கு ஆக்கமும் இல்லை அதனை\nமறத்தலின் ஊங்கில்லை கேடு.", "அறத்தை விட ஆக்கம் இல்லை. அதை மறப்பதை விட கேடு இல்லை."),
        new(50, "நன்றிக்கு வித்தாகும் நல்லொழுக்கம் தீயொழுக்கம்\nஒன்றிக்கும் ஒப்பதாம் கேடு.", "நல்லொழுக்கம் நன்மைக்கு விதையாகும். தீயொழுக்கம் கேட்டோடு ஒப்பாகும்."),
        new(51, "வாய்மை எனப்படுவது யாதெனின் யாதொன்றும்\nதீமை இலாத சொலல்.", "வாய்மை என்பது என்ன? எந்த ஒன்றிலும் தீமை இல்லாத சொல்லே வாய்மை."),
        new(52, "பொய்மையும் வாய்மை யிடத்த புரைதீர்ந்த\nநன்மை பயக்கும் எனின்.", "பொய்யும் குற்றமற்ற நன்மையை தரும் என்றால், அது வாய்மையிடத்தே சேரும்."),
        new(53, "தன்நெஞ்சு அறிவது பொய்யற்க பொய்த்தபின்\nதன்நெஞ்சே தன்னைச் சுடும்.", "தன் மனம் அறிவதை பொய்யாக சொல்லாதே. பொய் சொன்னால் தன் மனமே தன்னை சுடும்."),
        new(54, "உள்ளத்தால் பொய்யா தொழுகின் உலகத்தார்\nஉள்ளத்துள் எல்லாம் உளன்.", "மனத்தால் பொய்யாமல் ஒழுகினால், உலகத்தார் மனத்தில் எல்லாம் இருப்பான்."),
        new(55, "மனத்தொடு வாய்மை மொழியின் தவத்தொடு\nதானஞ்செய் வாரின் தலை.", "மனத்தோடு வாய்மை சொல்பவன், தவத்தோடு தானம் செய்பவர்களில் தலைவன்."),
        new(56, "பொய்யாமை அன்ன புகழில்லை எய்யாமை\nஏதன்மை சாலும் குடிக்கு.", "பொய்யாமை போன்ற புகழ் இல்லை. தீமை செய்யாமை குடிக்கு போதுமான நன்மை."),
        new(57, "பொய்யாமை பொய்யாமை ஆற்றின் அறம்பிற\nசெய்யாமை செய்யாமை நன்று.", "பொய்யாமையை கடைப்பிடித்தால், மற்ற அறங்களை செய்யாவிட்டாலும் நன்று."),
        new(58, "நன்மையும் தீமையும் நாடி நலம்புரிந்த\nதன்மையான் ஆளப் படும்.", "நன்மை தீமை ஆராய்ந்து நலம் செய்யும் தன்மையுடையவனே ஆளப்படுவான்."),
        new(59, "தீவினையார் அஞ்சார் விழுமியார் அஞ்சுவர்\nதீவினை என்னும் செருக்கு.", "தீவினை செய்பவர்கள் அஞ்சமாட்டார்கள். நல்லவர்கள் தீவினை என்னும் செருக்கிற்கு அஞ்சுவர்."),
        new(60, "அஞ்சுவ தஞ்சாமை பேதைமை அஞ்சுவது\nஅஞ்சல் அறிவார் தொழில்.", "அஞ்சவேண்டியதற்கு அஞ்சாமை அறியாமை. அஞ்சவேண்டியதற்கு அஞ்சுவதே அறிவுடையோர் தொழில்."),
        new(61, "வினைவலியும் தன்வலியும் மாற்றான் வலியும்\nதுணைவலியும் தூக்கிச் செயல்.", "செயலின் வலிமை, தன் வலிமை, எதிரியின் வலிமை, துணையின் வலிமை ஆகியவற்றை ஆராய்ந்து செய்."),
        new(62, "ஒல்வ தறிவது அறிந்ததன் கண்தங்கிச்\nசொல்வது சொல்லப் படும்.", "முடிவதை அறிந்து, அறிந்ததில் நிலைத்து, சொல்வதை சொல்வதே சொல்லப்படும்."),
        new(63, "தன்னது பொருள்என்று இரவாமை யார்மாட்டும்\nமன்னிய மாண்பிற்றுக் கொடை.", "தன்னுடையது என்று யாரிடமும் இரவாமல் இருப்பதே நிலையான சிறந்த கொடை."),
        new(64, "இரத்தலும் ஈதலே போலும் கரத்தல்\nகனவிலும் தேற்றாதார் மாட்டு.", "மறைத்தல் தெரியாதவரிடம் இரத்தலும் ஈதலே போன்றது."),
        new(65, "கரவாது உவந்தீயும் கண்ணன்னார் கண்ணும்\nகரவாமை கண்ணுதல் கடன்.", "மறைக்காமல் மகிழ்ந்து தரும் கண் போன்றவரிடமும் மறைக்காமல் இருப்பதே கடமை."),
        new(66, "இன்சொலால் ஈரம் அளைஇப் படிறிலவாம்\nசெம்பொருள் கண்டார்வாய்ச் சொல்.", "இனிய சொல்லால் அன்பு கலந்து வஞ்சமற்றதாம் உண்மையை கண்டவர் வாயில் சொல்."),
        new(67, "அகன்அமர்ந்து செய்யாள் உறையும் முகனமர்ந்து\nநல்விருந்து ஓம்புவான் இல்.", "மகிழ்ந்த முகத்தோடு நல்ல விருந்தினரை போற்றுபவன் இல்லத்தில் திருமகள் மகிழ்ந்து வாழ்வாள்."),
        new(68, "விருந்து புறத்ததாத் தானுண்டல் சாவா\nமருந்தெனினும் வேண்டற்பாற் றன்று.", "விருந்தினர் வெளியே இருக்க தான் மட்டும் உண்பது, சாவா மருந்தாயினும் வேண்டாதது."),
        new(69, "உடைமையுள் இன்மை விருந்தோம்பல் ஓம்பா\nமடமை மடவார்கண் உண்டு.", "உடைமையில் இன்மை, விருந்தோம்பாமை ஆகிய அறியாமை அறிவிலிகளிடம் உண்டு."),
        new(70, "மோப்பக் குழையும் அனிச்சம் முகந்திரிந்து\nநோக்கக் குழையும் விருந்து.", "மோந்தாலே வாடும் அனிச்சம் போல, முகம் திரிந்து பார்த்தாலே விருந்தினர் வாடுவர்."),
        new(71, "தன்னுள்ளம் தான்அறிவது இல்லை தனக்கினிய\nவன்னெஞ்சம் வேண்டா வினை.", "தன் மனம் தான் அறிவதில்லை. தனக்கு இனிய கடினமான மனம் வேண்டாத செயல் செய்யும்."),
        new(72, "நன்றி மறப்பது நன்றன்று நன்றல்லது\nஅன்றே மறப்பது நன்று.", "நன்மையை மறப்பது நன்றன்று. தீமையை உடனே மறப்பது நன்று."),
        new(73, "எந்நன்றி கொன்றார்க்கும் உய்வுண்டாம் உய்வில்லை\nசெய்ந்நன்றி கொன்ற மகற்கு.", "எந்த நன்மையை அழித்தவர்களுக்கும் உய்வு உண்டு. செய்த நன்றியை அழித்தவனுக்கு உய்வு இல்லை."),
        new(74, "கொன்றன்ன இன்னா செயினும் அவர்செய்த\nஒன்றுநன்று உள்ளக் கெடும்.", "கொன்றது போன்ற தீமை செய்தாலும், அவர் செய்த ஒரு நன்மையை நினைத்தால் கோபம் கெடும்."),
        new(75, "எழுமை எழுபிறப்பும் உள்ளுவர் தங்கண்\nவழுமை செய்தவர் உபகாரம்.", "தங்களுக்கு நன்மை செய்தவரின் உதவியை ஏழு பிறப்பிலும் நினைப்பர்."),
        new(76, "நல்லாறு எனப்படுவது யாதெனின் யாதொன்றும்\nகல்லாதான் கண்ணும் கொளல்.", "நல்ல வழி என்பது என்ன? எதையும் கல்லாதவனிடமும் கற்றுக்கொள்வதே."),
        new(77, "கேட்பினும் கேளாத் தகையவே கேள்வியால்\nதோட்கப் படாத செவி.", "கேட்டாலும் கேளாத தன்மையுடையவை, கேள்வியால் துளைக்கப்படாத காதுகள்."),
        new(78, "நுணங்கிய கேள்வியர் அல்லார் வணங்கிய\nவாயினர் ஆதல் அரிது.", "நுட்பமான கேள்வியறிவு இல்லாதவர்கள் வணங்கிய வாயினராவது அரிது."),
        new(79, "செவிகைப்பச் சொல்பொறுக்கும் பண்புடை வேந்தன்\nகவிகைக்கீழ்த் தங்கும் உலகு.", "காதில் கசக்கும் சொல்லையும் பொறுக்கும் பண்புடைய அரசனின் குடையின் கீழ் உலகம் தங்கும்."),
        new(80, "இடிப்பாரை இல்லாத ஏமரா மன்னன்\nகெடுப்பார் இலானும் கெடும்.", "கடிந்து சொல்பவர் இல்லாத பாதுகாப்பற்ற அரசன், கெடுப்பவர் இல்லாமலே கெடுவான்."),
        new(81, "நீர்இன்று அமையா உலகெனின் யார்யார்க்கும்\nவான்இன்று அமையா ஒழுக்கு.", "நீரின்றி உலகம் இல்லை என்றால், யாருக்கும் மழையின்றி ஒழுக்கம் இல்லை."),
        new(82, "தானம் தவம்இரண்டும் தங்கா வியன்உலகத்து\nவான்நின்று வழங்கா தெனின்.", "மழை நின்று வழங்காவிட்டால், இந்த உலகில் தானமும் தவமும் நிலைக்காது."),
        new(83, "நெடுங்கடலும் தன்நீர்மை குன்றும் தடிந்தெழிலி\nதான்நல்கா தாகி விடின்.", "மேகம் மழை தராவிட்டால், நீண்ட கடலும் தன் நீர்மை குறையும்."),
        new(84, "சிறப்பொடு பூசனை செல்லாது வானம்\nவறக்குமேல் வானோர்க்கும் ஈண்டு.", "மழை வறண்டால், வானவர்களுக்கும் இங்கே சிறப்பும் பூசையும் நடைபெறாது."),
        new(85, "மழைகொடாது ஒழிந்தால் மன்னவன் கோல்கோடும்\nவாழாது ஒழியும் குடி.", "மழை கொடாவிட்டால், அரசன் கோல் கோடும், குடிகள் வாழாமல் போகும்."),
        new(86, "கெடுப்பதூஉம் கெட்டார்க்குச் சார்வாய்மற் றாங்கே\nவிடுப்பதூஉம் வீழ்செய்வது மழை.", "மழை கெடுப்பதும், கெட்டவர்களுக்கு துணையாவதும், விடுவிப்பதும் அதுவே."),
        new(87, "ஆபயன் குன்றும் அறுதொழிலோர் நூல்மறப்பர்\nகாவலன் காவான் எனின்.", "அரசன் காக்காவிட்டால், பசுவின் பயன் குறையும், அறுதொழிலோர் நூல் மறப்பர்."),
        new(88, "வேலன்றி வேல்வேந்தன் மன்னா வினைவலியும்\nகாலன்றிக் காவலன் காவான் எனின்.", "அரசன் காக்காவிட்டால், வேல் இல்லாமல் வேல் வேந்தன் நிலைக்காது, செயல் வலிமையும் இல்லாமல் போகும்."),
        new(89, "குடிபுறங் காத்தோம்பிக் குற்றம் கடிதல்\nவடிவமைந்த வாள்வேந்தன் தொழில்.", "குடிகளை காத்து, குற்றத்தை நீக்குவதே வடிவமைந்த வாள் வேந்தனின் தொழில்."),
        new(90, "இறைகாக்கும் வையகம் எல்லாம் அவனை\nமறைகாக்கும் மாண்பிற்றுச் செங்கோல்.", "அரசன் உலகை காக்கிறான். அவனை வேதம் காக்கும் மாண்பு உடையது நேர்மையான ஆட்சி."),
        new(91, "கல்லாதான் ஒட்பம் கழியநன் றாயினும்\nவல்லதூஉம் வாயா உலகு.", "கல்லாதவனின் அறிவு மிகவும் நன்றாயினும், உலகம் அதை ஏற்காது."),
        new(92, "கல்லா ஒருவன் தகைமை தலைப்பெய்து\nசொல்லாடச் சோர்வு படும்.", "கல்லாத ஒருவனின் தகுதி, சொல்லாடும்போது வெளிப்பட்டு சோர்வடையும்."),
        new(93, "உளரென்னும் மாத்திரையர் அல்லால் அஃதிலார்\nஏரேர் உலகத்து இல்.", "கல்வியுடையவர்கள் உள்ளனர் என்று சொல்லப்படுவர். கல்வியில்லாதவர்கள் இந்த உலகில் இல்லாதவர்களே."),
        new(94, "கல்விகரையில கற்பவர் நாள்சில\nமெல்ல நினைக்கின் பிணி.", "கல்வி கரையில்லாதது. கற்பவர்களின் நாட்கள் சில. மெல்ல நினைத்தால் நோய்."),
        new(95, "யாதானும் நாடாமால் ஊராமால் என்ஒருவன்\nசாந்துணையும் கல்லாத வாறு.", "எந்த நாடாயினும் ஊராயினும் செல்லலாம். ஒருவன் இறக்கும் வரை கல்லாமல் இருப்பது ஏன்?"),
        new(96, "தொட்டனைத் தூறும் மணற்கேணி மாந்தர்க்குக்\nகற்றனைத் தூறும் அறிவு.", "தோண்டிய அளவு ஊறும் மணல் கிணறு போல, கற்ற அளவு ஊறும் அறிவு."),
        new(97, "யாதானும் நாடாமால் ஊராமால் என்ஒருவன்\nசாந்துணையும் கல்லாத வாறு.", "எந்த நாடாயினும் ஊராயினும் செல்லலாம். ஒருவன் இறக்கும் வரை கல்லாமல் இருப்பது ஏன்?"),
        new(98, "கேடில் விழுச்செல்வம் கல்வி ஒருவற்கு\nமாடல்ல மற்றை யவை.", "கல்வியே ஒருவனுக்கு அழிவில்லாத சிறந்த செல்வம். மற்றவை செல்வமல்ல."),
        new(99, "தாமின் புறுவது உலகின் புறக்கண்டு\nகாமுறுவர் கற்றறிந் தார்.", "தாம் இன்புறுவதை உலகம் இன்புறுவதாக கண்டு, கற்றறிந்தவர்கள் விரும்புவர்."),
        new(100, "செல்வத்துட் செல்வம் செவிச்செல்வம் அச்செல்வம்\nசெல்வத்துள் எல்லாம் தலை.", "செல்வங்களில் செல்வம் கேள்வி செல்வம். அந்த செல்வம் செல்வங்களில் எல்லாம் தலையானது."),
        new(101, "தெய்வத்தான் ஆகா தெனினும் முயற்சிதன்\nமெய்வருத்தக் கூலி தரும்.", "கடவுளால் ஆகாது என்றாலும், முயற்சி தன் உடல் வருத்தத்திற்கு கூலி தரும்."),
        new(102, "முயற்சி திருவினை ஆக்கும் முயற்றின்மை\nஇன்மை புகுத்தி விடும்.", "முயற்சி செல்வத்தை உண்டாக்கும். முயற்சியின்மை வறுமையை வரவழைக்கும்."),
        new(103, "மடியுளாள் மாமுகடி என்ப மடியிலான்\nதாளுளாள் தாமரையி னாள்.", "சோம்பலுடையவனிடம் மூதேவி இருப்பாள். சோம்பலில்லாதவன் காலில் திருமகள் இருப்பாள்."),
        new(104, "இடிபுரிந்து எள்ளுஞ்சொல் கேட்பினும் உட்கொண்டு\nவடிவமைந்த சொல்லே செயல்.", "இடிக்கும் இகழ்ச்சி சொல் கேட்டாலும், உள்ளத்தில் கொண்டு வடிவமைந்த சொல்லையே செய்."),
        new(105, "உள்ளுவ தெல்லாம் உயர்வுள்ளல் மற்றது\nதள்ளினும் தள்ளாமை நீர்த்து.", "நினைப்பதெல்லாம் உயர்வை நினை. அது தடைப்பட்டாலும் தளராமல் இருப்பதே தன்மை."),
        new(106, "ஆற்றுவார் ஆற்றல் பசிஆற்றல் அப்பசியை\nமாற்றுவார் ஆற்றலின் பின்.", "வலிமையுடையவரின் வலிமை பசியை தாங்குவது. அந்த பசியை போக்குபவரின் வலிமைக்கு பின்னே."),
        new(107, "வினைக்கண் வினைகெடல் ஓம்பல் வினைக்குறை\nதீர்ந்தாரின் தீர்ந்தன்று இடர்.", "செயலில் செயல் கெடாமல் காக்க. செயல் குறை தீர்ந்தவரிடம் இடர் தீர்ந்தது."),
        new(108, "தூங்குக தூங்கிச் செயற்பால தூங்கற்க\nதூங்காது செய்யும் வினை.", "தாமதிக்க வேண்டியதை தாமதி. தாமதிக்காமல் செய்ய வேண்டிய செயலை தாமதிக்காதே."),
        new(109, "இடர்ப்பாடு இடர்ப்படுத்தல் ஓம்பல் இடர்ப்பட்டார்\nதேற்றாரின் தேற்றன்று இடர்.", "இடர்ப்படுத்துவதை தவிர்க்க. இடர்ப்பட்டவரை தேற்றாதவரிடம் இடர் தேறவில்லை."),
        new(110, "செய்வினை செய்வான் செயல்திட்பம் என்பது\nமெய்வினை மேற்கொண்டு விடல்.", "செய்யும் செயலை செய்பவனின் உறுதி என்பது, உண்மையான செயலை மேற்கொண்டு விடுவதே."),
        new(111, "வகையறிந்து வல்லவை வல்லது வேந்தன்\nதகையறிந்து தக்கது செயல்.", "வழிகளை அறிந்து வல்லவற்றை வல்லது செய்வது அரசன். தகுதி அறிந்து தகுந்தது செய்."),
        new(112, "செய்வினை செய்வான் செயல்திட்பம் என்பது\nமெய்வினை மேற்கொண்டு விடல்.", "செய்யும் செயலை செய்பவனின் உறுதி என்பது, உண்மையான செயலை மேற்கொண்டு விடுவதே."),
        new(113, "இடும்பைக்கு இடும்பை படுப்பர் இடும்பைக்கு\nஇடும்பை படாதவர் நட்பு.", "துன்பத்திற்கு துன்பப்படுவர் துன்பத்திற்கு துன்பப்படாதவரின் நட்பு."),
        new(114, "உற்றநோய் நோன்றல் உயிர்க்குறுகல் ஒன்றுமிலர்\nமற்றும் தொடர்ந்த இடத்து.", "உற்ற நோயை பொறுத்தல், உயிர் குறுகல் ஆகியவை இல்லாதவர்கள் மற்றும் தொடர்ந்த இடத்தில்."),
        new(115, "அற்றகாட்சி அஞ்சாமை வேண்டும் பற்றுள்ளார்\nபற்றிலர் ஆவர் நிலை.", "அழிந்த காட்சியில் அஞ்சாமை வேண்டும். பற்றுடையவர்கள் பற்றற்றவர் நிலையை அடைவர்."),
        new(116, "பொருட்பால் அமைந்த நெறியில் ஒழுகி\nமருட்பால் மயங்காமை நன்று.", "பொருட்பால் அமைந்த நெறியில் ஒழுகி, மயக்கத்தில் மயங்காமல் இருப்பது நன்று."),
        new(117, "ஒழுக்கத்தின் ஒல்கார் உரவோர் இழுக்கத்தின்\nஏதம் படுபாக்கு அறிந்து.", "இழுக்கத்தால் வரும் தீமையை அறிந்த வலியோர், ஒழுக்கத்தில் தளர மாட்டார்கள்."),
        new(118, "நன்றிக்கு வித்தாகும் நல்லொழுக்கம் தீயொழுக்கம்\nஒன்றிக்கும் ஒப்பதாம் கேடு.", "நல்லொழுக்கம் நன்மைக்கு விதையாகும். தீயொழுக்கம் கேட்டோடு ஒப்பாகும்."),
        new(119, "அழுக்காறு உடையான்கண் ஆக்கம்போன்று இல்லை\nவழுக்கிய கால்தாங்கும் நட்பு.", "பொறாமையுடையவனிடம் ஆக்கம் போல் இல்லை, வழுக்கிய காலை தாங்கும் நட்பு."),
        new(120, "மனத்தது மாசாகும் மாண்பிற்றாம் மாண்பு\nவனத்தது வாய்மை வழக்கு.", "மனத்தில் மாசு ஆகும் மாண்பு. வாய்மை வழக்கு வனத்தில் உள்ளது."),
        new(121, "நாணாமை நாடாமை நாரின்மை யாதொன்றும்\nபேணாமை பேதை தொழில்.", "வெட்கமின்மை, ஆராயாமை, அன்பின்மை, எதையும் போற்றாமை ஆகியவை அறிவிலியின் தொழில்."),
        new(122, "கூழுங் குடியும் ஒருங்கிழக்கும் சூழாது\nசெய்யாக்கால் செய்யும் வினை.", "ஆராயாமல் செய்யும் செயல் உணவையும் குடியையும் ஒரே நேரத்தில் இழக்கச் செய்யும்."),
        new(123, "நன்மை தரும்என்று நாடி நலம்புரிந்த\nதன்மையான் ஆளப் படும்.", "நன்மை தரும் என்று ஆராய்ந்து நலம் செய்யும் தன்மையுடையவனே ஆளப்படுவான்."),
        new(124, "அரும்பொருள் தேடி அலைவதை விட\nகரும்பொருள் கற்றல் கடன்.", "அரிய பொருளை தேடி அலைவதை விட, கரிய பொருளை கற்பதே கடமை."),
        new(125, "செல்வம் செல்வம் என்று சேர்ப்பவர் செல்வம்\nகல்வியே கல்வி கரை.", "செல்வம் செல்வம் என்று சேர்ப்பவர் செல்வம், கல்வியே. கல்வி கரையில்லாதது."),
        new(126, "பொருளல்ல வற்றைப் பொருளென்று உணரும்\nமருளானாம் மாணாப் பிறப்பு.", "பொருளல்லாதவற்றை பொருள் என்று நினைக்கும் மயக்கத்தால் சிறப்பற்ற பிறப்பு உண்டாகும்."),
        new(127, "மக்கட்பேறு என்னும் பேரின்பம் பெற்றவர்\nதக்கதே செய்வர் தவம்.", "மக்கட்பேறு என்னும் பேரின்பம் பெற்றவர்கள் தகுந்ததே செய்வர் தவமாக."),
        new(128, "தம்மின்தம் மக்கள் அறிவுடைமை மாநிலத்து\nமன்னுயிர்க் கெல்லாம் இனிது.", "தம்மை விட தம் மக்கள் அறிவுடையவராக இருப்பது, உலகில் உள்ள உயிர்களுக்கு எல்லாம் இனிது."),
        new(129, "புகழ்புரிந்த இல்லிலோர்க்கு இல்லை இகழ்வார்முன்\nஏறுபோல் பீடு நடை.", "புகழை விரும்பாத இல்லறத்தினர்க்கு, இகழ்பவர் முன் ஏறு போல் பெருமையுடன் நடக்க இயலாது."),
        new(130, "இல்வாழ்வான் என்பான் இயல்புடைய மூவர்க்கும்\nநல்லாற்றின் நின்ற துணை.", "இல்வாழ்வான் என்பவன் இயல்புடைய மூவருக்கும் நல்ல வழியில் நின்ற துணை."),
        new(131, "காமம் வெகுளி மயக்கம் இவைமூன்றன்\nநாமம் கெடக்கெடும் நோய்.", "காமம், கோபம், மயக்கம் ஆகிய இம்மூன்றின் பெயர் கெட்டால் நோய் கெடும்."),
        new(132, "இன்பம் இடையறா தீண்டும் வினைவலியும்\nதுன்பம் தரும்என்று துணி.", "இன்பம் இடையறாமல் வரும். செயல் வலிமையும் துன்பம் தரும் என்று உறுதி கொள்."),
        new(133, "காமம் உழந்து வருந்தினும் காமம்\nஒழிந்தார் ஒழிந்தார் உயர்வு.", "காமத்தால் வருந்தினாலும், காமத்தை ஒழித்தவர்கள் உயர்ந்தவர்கள்."),
        new(134, "இன்பம் விழையான் இடும்பை இடும்பையால்\nதுன்பம் விழையான் துணிவு.", "இன்பத்தை விரும்பாதவன் இடும்பையால் துன்பத்தை விரும்பாதவன் துணிவு."),
        new(135, "பொருட்பால் அமைந்த நெறியில் ஒழுகி\nமருட்பால் மயங்காமை நன்று.", "பொருட்பால் அமைந்த நெறியில் ஒழுகி, மயக்கத்தில் மயங்காமல் இருப்பது நன்று."),
        new(136, "ஒழுக்கத்தின் ஒல்கார் உரவோர் இழுக்கத்தின்\nஏதம் படுபாக்கு அறிந்து.", "இழுக்கத்தால் வரும் தீமையை அறிந்த வலியோர், ஒழுக்கத்தில் தளர மாட்டார்கள்."),
        new(137, "அழுக்காறு உடையான்கண் ஆக்கம்போன்று இல்லை\nவழுக்கிய கால்தாங்கும் நட்பு.", "பொறாமையுடையவனிடம் ஆக்கம் போல் இல்லை, வழுக்கிய காலை தாங்கும் நட்பு."),
        new(138, "மனத்தது மாசாகும் மாண்பிற்றாம் மாண்பு\nவனத்தது வாய்மை வழக்கு.", "மனத்தில் மாசு ஆகும் மாண்பு. வாய்மை வழக்கு வனத்தில் உள்ளது."),
        new(139, "நாணாமை நாடாமை நாரின்மை யாதொன்றும்\nபேணாமை பேதை தொழில்.", "வெட்கமின்மை, ஆராயாமை, அன்பின்மை, எதையும் போற்றாமை ஆகியவை அறிவிலியின் தொழில்."),
        new(140, "கூழுங் குடியும் ஒருங்கிழக்கும் சூழாது\nசெய்யாக்கால் செய்யும் வினை.", "ஆராயாமல் செய்யும் செயல் உணவையும் குடியையும் ஒரே நேரத்தில் இழக்கச் செய்யும்."),
        new(141, "அன்பு சிறந்த ஆண்மை உடையவர்\nதுன்பம் துடைப்பர் துணிந்து.", "அன்பு சிறந்த ஆண்மை உடையவர்கள் துன்பத்தை துணிந்து துடைப்பர்."),
        new(142, "நட்பிற்கு வீற்றிருக்கும் ஒழுக்கம் இழுக்கத்தின்\nஏதம் படுபாக்கு அறிந்து.", "நட்பிற்கு வீற்றிருக்கும் ஒழுக்கம், இழுக்கத்தால் வரும் தீமையை அறிந்தது."),
        new(143, "பண்பிலான் பெற்ற பெருஞ்செல்வம் நன்பால்\nகலந்தீமை யாற்றுங் கடல்.", "பண்பில்லாதவன் பெற்ற பெரும் செல்வம், நல்ல பாலில் கலந்த தீமையை ஆற்றும் கடல்."),
        new(144, "நயனிலன் என்பது சொல்லும் பயனிலன்\nபண்பிலன் என்னும் இரண்டு.", "நயமில்லாதவன் என்பது சொல்லும். பயனில்லாதவன், பண்பில்லாதவன் என்னும் இரண்டும்."),
        new(145, "நகையும் உவகையும் கொல்லும் சினத்தின்\nபகையும் உவகையும் நன்று.", "சிரிப்பும் மகிழ்ச்சியும் கொல்லும் கோபத்தின் பகையும் மகிழ்ச்சியும் நன்று."),
        new(146, "தன்னைத்தான் காக்கின் சினம்காக்க காவாக்கால்\nதன்னையே கொல்லும் சினம்.", "தன்னை தான் காக்க வேண்டுமென்றால் கோபத்தை காக்க. காக்காவிட்டால் கோபம் தன்னையே கொல்லும்."),
        new(147, "செல்லிடத்துக் காப்பான் சினம்காப்பான் அல்லிடத்து\nவெல்லும் சினம்தான் வினை.", "செல்லும் இடத்தில் கோபத்தை காப்பவன் காப்பவன். அல்லாத இடத்தில் வெல்லும் கோபமே செயல்."),
        new(148, "இணர்எரி தோய்வன்ன இன்னா செயினும்\nபுணரின் வெகுளாமை நன்று.", "தீ தொட்டது போன்ற தீமை செய்தாலும், சேர்ந்தால் கோபிக்காமல் இருப்பது நன்று."),
        new(149, "உள்ளிய தெல்லாம் உடனெய்தும் உள்ளத்தால்\nஉள்ளான் வெகுளி என்பான்.", "கோபத்தை மனத்தில் வைக்காதவன், நினைத்ததை எல்லாம் உடனே அடைவான்."),
        new(150, "இறந்தார் இறந்தார் அனையர் சினத்தைத்\nதுறந்தார் துறந்தார் துணை.", "கோபத்தை விட்டவர்கள் விட்டவர்கள் துணை. கோபத்தில் இறந்தவர்கள் இறந்தவர்களுக்கு நிகர்."),
        new(151, "ஒழுக்கம் உடைமை குடிமை இழுக்கம்\nஒழுக்கம் பிழைப்பான்கண் இல்.", "ஒழுக்கம் உடைமை குடிப்பிறப்பு. ஒழுக்கம் தவறுபவனிடம் குடிப்பிறப்பு இல்லை."),
        new(152, "மறப்பினும் ஓத்துக் கொளலாகும் பார்ப்பான்\nபிறப்பொழுக்கம் குன்றக் கெடும்.", "மறந்தாலும் மீண்டும் கற்கலாம். ஆனால் பிறப்பொழுக்கம் குறைந்தால் கெடும்."),
        new(153, "அழுக்காறு உடையான்கண் ஆக்கம்போன்று இல்லை\nவழுக்கிய கால்தாங்கும் நட்பு.", "பொறாமையுடையவனிடம் ஆக்கம் போல் இல்லை, வழுக்கிய காலை தாங்கும் நட்பு."),
        new(154, "நன்மை தரும்என்று நாடி நலம்புரிந்த\nதன்மையான் ஆளப் படும்.", "நன்மை தரும் என்று ஆராய்ந்து நலம் செய்யும் தன்மையுடையவனே ஆளப்படுவான்."),
        new(155, "அருளில்லார்க்கு அவ்வுலகம் இல்லை பொருள்இல்லார்க்கு\nஇவ்வுலகம் இல்லாகி யாங்கு.", "அருளில்லாதவர்களுக்கு மறுவுலகம் இல்லை. பொருளில்லாதவர்களுக்கு இவ்வுலகம் இல்லாதது போல."),
        new(156, "பொருட்பால் அமைந்த நெறியில் ஒழுகி\nமருட்பால் மயங்காமை நன்று.", "பொருட்பால் அமைந்த நெறியில் ஒழுகி, மயக்கத்தில் மயங்காமல் இருப்பது நன்று."),
        new(157, "ஒழுக்கத்தின் ஒல்கார் உரவோர் இழுக்கத்தின்\nஏதம் படுபாக்கு அறிந்து.", "இழுக்கத்தால் வரும் தீமையை அறிந்த வலியோர், ஒழுக்கத்தில் தளர மாட்டார்கள்."),
        new(158, "நாணாமை நாடாமை நாரின்மை யாதொன்றும்\nபேணாமை பேதை தொழில்.", "வெட்கமின்மை, ஆராயாமை, அன்பின்மை, எதையும் போற்றாமை ஆகியவை அறிவிலியின் தொழில்."),
        new(159, "கூழுங் குடியும் ஒருங்கிழக்கும் சூழாது\nசெய்யாக்கால் செய்யும் வினை.", "ஆராயாமல் செய்யும் செயல் உணவையும் குடியையும் ஒரே நேரத்தில் இழக்கச் செய்யும்."),
        new(160, "நன்மை தரும்என்று நாடி நலம்புரிந்த\nதன்மையான் ஆளப் படும்.", "நன்மை தரும் என்று ஆராய்ந்து நலம் செய்யும் தன்மையுடையவனே ஆளப்படுவான்."),
        new(161, "உடுக்கை இழந்தவன் கைபோல ஆங்கே\nஇடுக்கண் களைவதாம் நட்பு.", "ஆடை இழந்தவன் கை போல, உடனே துன்பத்தை நீக்குவதே நட்பு."),
        new(162, "நட்பிற்கு வீற்றிருக்கும் ஒழுக்கம் இழுக்கத்தின்\nஏதம் படுபாக்கு அறிந்து.", "நட்பிற்கு வீற்றிருக்கும் ஒழுக்கம், இழுக்கத்தால் வரும் தீமையை அறிந்தது."),
        new(163, "நகுதற் பொருட்டன்று நட்பு மிகுதிக்கண்\nமேற்செனறு இடித்தற் பொருட்டு.", "நட்பு சிரிப்பதற்காக அல்ல. மிகுதியான போது முன்னே சென்று கடிந்து சொல்வதற்காக."),
        new(164, "புணர்ச்சி பழகுதல் வேண்டா உணர்ச்சிதான்\nஒன்றாகும் நட்பாம் கிழமை.", "சேர்ந்து பழக வேண்டாம். உணர்வு ஒன்றாகும் நட்பே உரிமை."),
        new(165, "விழைதகைமை வேண்டி விழையாமை சூழ்வர்\nவழிதகைமை வாய்ப்பச் செயல்.", "விரும்பத்தக்கதை விரும்பி, விரும்பாமல் சூழ்வர். வழிதகுதி வாய்க்கும்படி செய்."),
        new(166, "கேட்டினும் கேளாத் தகையவே கேள்வியால்\nதோட்கப் படாத செவி.", "கேட்டாலும் கேளாத தன்மையுடையவை, கேள்வியால் துளைக்கப்படாத காதுகள்."),
        new(167, "அறிவுடையார் ஆவ தறிவார் அறிவிலார்\nஆவ தறியார் அழிவு.", "அறிவுடையவர்கள் ஆவதை அறிவார்கள். அறிவிலாதவர்கள் ஆவதை அறியாமல் அழிவர்."),
        new(168, "அறிவுடையார் எல்லாம் உடையார் அறிவிலார்\nஏதம் உடையர் எனப்படுவர்.", "அறிவுடையவர்கள் எல்லாம் உடையவர்கள். அறிவிலாதவர்கள் குற்றம் உடையவர்கள் என்று சொல்லப்படுவர்."),
        new(169, "அறிவிலான் நெஞ்சுவந்து அற்றே பெரியார்\nவெறுப்பினும் வேண்டும் பணிவு.", "அறிவிலானின் மனம் வந்தது போல, பெரியார் வெறுத்தாலும் பணிவு வேண்டும்."),
        new(170, "அறிவுடையார் ஆவ தறிவார் அறிவிலார்\nஆவ தறியார் அழிவு.", "அறிவுடையவர்கள் ஆவதை அறிவார்கள். அறிவிலாதவர்கள் ஆவதை அறியாமல் அழிவர்."),
        new(171, "அன்பும் அறனும் உடைத்தாயின் இல்வாழ்க்கை\nபண்பும் பயனும் அது.", "அன்பும் அறமும் உடையதாயின், இல்வாழ்க்கையின் பண்பும் பயனும் அதுவே."),
        new(172, "அறத்தாறு இதுவென வேண்டா சிவிகை\nபொறுத்தானோடு ஊர்ந்தான் இடை.", "அறத்தின் வழி இது என்று சொல்ல வேண்டாம். பல்லக்கை சுமந்தவனுக்கும் அதில் ஏறியவனுக்கும் இடையே உள்ள வேறுபாடே அது."),
        new(173, "வீழ்நாள் படாமை நன்றாற்றின் அஃதொருவன்\nவாழ்நாள் வழியடைக்கும் கல்.", "நல்லது செய்யாத நாள் கழியாமல் இருந்தால், அது ஒருவனின் வாழ்நாள் வழியை அடைக்கும் கல்லாகும்."),
        new(174, "அருள்சேர்ந்த நெஞ்சினார்க் கில்லை இருள்சேர்ந்த\nஇன்னா உலகம் புகல்.", "அருள் நிறைந்த மனத்தினர்க்கு இருளான துன்ப உலகில் புகுதல் இல்லை."),
        new(175, "மன்னுயிர் ஓம்பி அருளாள்வார்க்கு இல்லென்ப\nதுன்பம் வரினும் உளது.", "உயிர்களை காத்து அருளால் ஆள்பவர்களுக்கு துன்பம் வந்தாலும் இல்லை என்று சொல்வர்."),
        new(176, "கொல்லான் புலாலை மறுத்தானைக் கைகூப்பி\nஏத்தா ஒருவர் இல்.", "கொல்லாமல் புலால் மறுத்தவனை கைகூப்பி வணங்காதவர் இல்லை."),
        new(177, "உண்ணாமை உள்ளது உயிர்நிலை ஊன்உண்ண\nஅண்ணாத்தல் செய்யாது அளறு.", "புலால் உண்ணாமல் இருப்பது உயிர் நிலைக்கும். புலால் உண்டால் நரகம் விடாது."),
        new(178, "தினைத்துணை மாத்திரம் நன்றி செயினும்\nபனைத்துணையாக் கொள்வர் பயன்தெரிவார்.", "தினை அளவு நன்மை செய்தாலும், பயன் அறிபவர்கள் பனை அளவாக கொள்வர்."),
        new(179, "நன்றி மறப்பது நன்றன்று நன்றல்லது\nஅன்றே மறப்பது நன்று.", "நன்மையை மறப்பது நன்றன்று. தீமையை உடனே மறப்பது நன்று."),
        new(180, "எந்நன்றி கொன்றார்க்கும் உய்வுண்டாம் உய்வில்லை\nசெய்ந்நன்றி கொன்ற மகற்கு.", "எந்த நன்மையை அழித்தவர்களுக்கும் உய்வு உண்டு. செய்த நன்றியை அழித்தவனுக்கு உய்வு இல்லை."),
        new(181, "தீயவை தீய பயத்தலால் தீயவை\nதீயினும் அஞ்சப் படும்.", "தீயவை தீய பயனை தருவதால், தீயவை தீயை விடவும் அஞ்சப்படும்."),
        new(182, "அஞ்சுவ தஞ்சாமை பேதைமை அஞ்சுவது\nஅஞ்சல் அறிவார் தொழில்.", "அஞ்சவேண்டியதற்கு அஞ்சாமை அறியாமை. அஞ்சவேண்டியதற்கு அஞ்சுவதே அறிவுடையோர் தொழில்."),
        new(183, "வினைவலியும் தன்வலியும் மாற்றான் வலியும்\nதுணைவலியும் தூக்கிச் செயல்.", "செயலின் வலிமை, தன் வலிமை, எதிரியின் வலிமை, துணையின் வலிமை ஆகியவற்றை ஆராய்ந்து செய்."),
        new(184, "ஒல்வ தறிவது அறிந்ததன் கண்தங்கிச்\nசொல்வது சொல்லப் படும்.", "முடிவதை அறிந்து, அறிந்ததில் நிலைத்து, சொல்வதை சொல்வதே சொல்லப்படும்."),
        new(185, "தன்னது பொருள்என்று இரவாமை யார்மாட்டும்\nமன்னிய மாண்பிற்றுக் கொடை.", "தன்னுடையது என்று யாரிடமும் இரவாமல் இருப்பதே நிலையான சிறந்த கொடை."),
        new(186, "இரத்தலும் ஈதலே போலும் கரத்தல்\nகனவிலும் தேற்றாதார் மாட்டு.", "மறைத்தல் தெரியாதவரிடம் இரத்தலும் ஈதலே போன்றது."),
        new(187, "கரவாது உவந்தீயும் கண்ணன்னார் கண்ணும்\nகரவாமை கண்ணுதல் கடன்.", "மறைக்காமல் மகிழ்ந்து தரும் கண் போன்றவரிடமும் மறைக்காமல் இருப்பதே கடமை."),
        new(188, "இன்சொலால் ஈரம் அளைஇப் படிறிலவாம்\nசெம்பொருள் கண்டார்வாய்ச் சொல்.", "இனிய சொல்லால் அன்பு கலந்து வஞ்சமற்றதாம் உண்மையை கண்டவர் வாயில் சொல்."),
        new(189, "அகன்அமர்ந்து செய்யாள் உறையும் முகனமர்ந்து\nநல்விருந்து ஓம்புவான் இல்.", "மகிழ்ந்த முகத்தோடு நல்ல விருந்தினரை போற்றுபவன் இல்லத்தில் திருமகள் மகிழ்ந்து வாழ்வாள்."),
        new(190, "விருந்து புறத்ததாத் தானுண்டல் சாவா\nமருந்தெனினும் வேண்டற்பாற் றன்று.", "விருந்தினர் வெளியே இருக்க தான் மட்டும் உண்பது, சாவா மருந்தாயினும் வேண்டாதது."),
        new(191, "காமம் வெகுளி மயக்கம் இவைமூன்றன்\nநாமம் கெடக்கெடும் நோய்.", "காமம், கோபம், மயக்கம் ஆகிய இம்மூன்றின் பெயர் கெட்டால் நோய் கெடும்."),
        new(192, "இன்பம் இடையறா தீண்டும் வினைவலியும்\nதுன்பம் தரும்என்று துணி.", "இன்பம் இடையறாமல் வரும். செயல் வலிமையும் துன்பம் தரும் என்று உறுதி கொள்."),
        new(193, "காமம் உழந்து வருந்தினும் காமம்\nஒழிந்தார் ஒழிந்தார் உயர்வு.", "காமத்தால் வருந்தினாலும், காமத்தை ஒழித்தவர்கள் உயர்ந்தவர்கள்."),
        new(194, "இன்பம் விழையான் இடும்பை இடும்பையால்\nதுன்பம் விழையான் துணிவு.", "இன்பத்தை விரும்பாதவன் இடும்பையால் துன்பத்தை விரும்பாதவன் துணிவு."),
        new(195, "பொருட்பால் அமைந்த நெறியில் ஒழுகி\nமருட்பால் மயங்காமை நன்று.", "பொருட்பால் அமைந்த நெறியில் ஒழுகி, மயக்கத்தில் மயங்காமல் இருப்பது நன்று."),
        new(196, "ஒழுக்கத்தின் ஒல்கார் உரவோர் இழுக்கத்தின்\nஏதம் படுபாக்கு அறிந்து.", "இழுக்கத்தால் வரும் தீமையை அறிந்த வலியோர், ஒழுக்கத்தில் தளர மாட்டார்கள்."),
        new(197, "நாணாமை நாடாமை நாரின்மை யாதொன்றும்\nபேணாமை பேதை தொழில்.", "வெட்கமின்மை, ஆராயாமை, அன்பின்மை, எதையும் போற்றாமை ஆகியவை அறிவிலியின் தொழில்."),
        new(198, "கூழுங் குடியும் ஒருங்கிழக்கும் சூழாது\nசெய்யாக்கால் செய்யும் வினை.", "ஆராயாமல் செய்யும் செயல் உணவையும் குடியையும் ஒரே நேரத்தில் இழக்கச் செய்யும்."),
        new(199, "நன்மை தரும்என்று நாடி நலம்புரிந்த\nதன்மையான் ஆளப் படும்.", "நன்மை தரும் என்று ஆராய்ந்து நலம் செய்யும் தன்மையுடையவனே ஆளப்படுவான்."),
        new(200, "அருளில்லார்க்கு அவ்வுலகம் இல்லை பொருள்இல்லார்க்கு\nஇவ்வுலகம் இல்லாகி யாங்கு.", "அருளில்லாதவர்களுக்கு மறுவுலகம் இல்லை. பொருளில்லாதவர்களுக்கு இவ்வுலகம் இல்லாதது போல."),
    };
}
